# Module defining shape classes and interfaces

interface IDrawable:
    def draw(self) -> str: ...

@abstract
class Shape:
    x: int
    y: int

    def __init__(self, x: int, y: int):
        self.x = x
        self.y = y

    @abstract
    def area(self) -> float: ...

    def position(self) -> str:
        return f"Position: ({{self.x}}, {{self.y}})"

class Rectangle(Shape):
    width: int
    height: int

    def __init__(self, x: int, y: int, width: int, height: int):
        super().__init__(x, y)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return float(self.width * self.height)

class Circle(Shape):
    radius: float

    def __init__(self, x: int, y: int, radius: float):
        super().__init__(x, y)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * (self.radius ** 2.0)

