# Utility module importing shapes and providing operations

from shapes import Shape, Rectangle, Circle

class ShapeStats:
    total_area: float
    count: int

    def __init__(self):
        self.total_area = 0.0
        self.count = 0

    def add_shape(self, shape: Shape):
        self.total_area += shape.area()
        self.count += 1

    def average_area(self) -> float:
        if self.count == 0:
            return 0.0
        return self.total_area / float(self.count)

    def report(self) -> str:
        return f"Analyzed {{self.count}} shapes, total area: {{self.total_area:.2f}}"

def create_square(x: int, y: int, size: int) -> Rectangle:
    return Rectangle(x, y, size, size)

def create_shapes() -> list[Shape]:
    shapes: list[Shape] = []
    shapes.append(Rectangle(0, 0, 10, 20))
    shapes.append(Circle(5, 5, 5.0))
    shapes.append(create_square(2, 3, 8))
    return shapes
